const alerts = $('Fetch Unprocessed Alerts').first().json;
const health = $('Fetch Health').first().json;
const errors = $('Fetch Error Summary').first().json;

// Parse alerts (could be array directly or wrapped)
const alertList = Array.isArray(alerts) ? alerts : (alerts.data || []);
const alertCount = alertList.length;

// Health status
const dbOk = health.core?.database === 'ok';
const redisOk = health.core?.redis === 'ok';
const llmCount = health.llm?.available || 0;
const llmTotal = health.llm?.total || 0;
const healthOk = health.status === 'ok';

// Error summary
const totalErrors = errors.totalErrors || errors.total || 0;
const topErrors = (errors.errors || errors.summary || []).slice(0, 3);

// Determine overall status
let color = 3066993; // green
let status = 'All Clear';
const issues = [];

if (!healthOk) {
  color = 15548997; // red
  status = 'UNHEALTHY';
  if (!dbOk) issues.push('Database DOWN');
  if (!redisOk) issues.push('Redis DOWN');
}

if (alertCount > 0) {
  const criticals = alertList.filter(a => a.severity === 'critical');
  if (criticals.length > 0) {
    color = 15548997; // red
    status = `${criticals.length} Critical Alert(s)`;
  } else {
    color = 16776960; // yellow
    status = `${alertCount} Unprocessed Alert(s)`;
  }
  alertList.forEach(a => issues.push(`[${a.severity}] ${a.title}`));
}

if (totalErrors > 10 && color === 3066993) {
  color = 16776960; // yellow
  if (status === 'All Clear') status = 'Elevated Errors';
}

// Build description
const lines = [];
lines.push(`**Status:** ${status}`);
lines.push(`**Health:** DB ${dbOk ? '✅' : '❌'} | Redis ${redisOk ? '✅' : '❌'} | LLM ${llmCount}/${llmTotal}`);
lines.push(`**Errors (4h):** ${totalErrors}`);

if (issues.length > 0) {
  lines.push('');
  lines.push('**Issues:**');
  issues.forEach(i => lines.push(`• ${i}`));
}

if (topErrors.length > 0 && totalErrors > 0) {
  lines.push('');
  lines.push('**Top Errors:**');
  topErrors.forEach(e => lines.push(`• ${e.message || e.error || 'Unknown'} (×${e.count || 1})`));
}

const description = lines.join('\n');

// Build alert resolution payloads if we should auto-resolve info alerts
const resolvePayloads = alertList
  .filter(a => a.severity === 'info' && a.source === 'manual')
  .map(a => ({ id: a.id, status: 'resolved', resolution: 'Auto-resolved by ops agent health check' }));

return [{ json: { color, description, alertCount, resolvePayloads, healthOk } }];
